        (id,tenant_id,url_sha256,source_id,source_url,title,slug,category,badge,read_time,seo_title,description,hero_angle,highlights_json,content,cta_text,hero_media_id,is_archived,created_at,updated_at)
       VALUES (
        'hiring-training-door-knockers-tips-for-success','usr_admin_demo','59b5e4cf93f2b1ceb9e7d5a35593382e88057860a96bc341b4d369519bc61c8f',NULL,'urn:contentforge-seed:hiring-training-door-knockers-tips-for-success','Hiring & Training Door Knockers: Tips for Success','/blog/hiring-training-door-knockers-tips-for-success',
        'Guides','Article','4 min read','Hiring & Training Door Knockers: Tips for Success | Acme','Average annual sales turnover sits at 35%. Learn how to build an unstoppable team by using mobile onboarding, gamification, and stress reduction.',
        'The Revolving Door Problem -- And How to Fix It','["Identify resilience and adaptability upfront during candidate interviews.","Implement a mobile-first onboarding track to put training resources directly in reps'' pockets.","Drive engagement using gamified leaderboards, point systems, and badge rewards.","Provide real-time coaching feedback and microlearning based on field analytics.","Reduce stress and early burnout using route optimization and clear commission visualizers."]','High rep attrition quietly drains company profits. By shifting from printed manuals to interactive, mobile-guided gamified experiences, you can shorten ramp-up times and motivate a new generation of field team members.',NULL,NULL,0,'2026-05-22T09:50:48.142Z','2026-05-22T09:50:48.142Z');
INSERT OR REPLACE INTO articles
        (id,tenant_id,url_sha256,source_id,source_url,title,slug,category,badge,read_time,seo_title,description,hero_angle,highlights_json,content,cta_text,hero_media_id,is_archived,created_at,updated_at)
       VALUES (
        'door-to-door-vs-digital-leads-where-to-invest-marketing-budget','usr_admin_demo','8774937af6aab1b726fa836ff85550f7b9834ee02ea18b6a3227e6897b0c3ff6',NULL,'urn:contentforge-seed:door-to-door-vs-digital-leads-where-to-invest-marketing-budget','Door-to-Door vs Digital Leads: Where to Invest','/blog/door-to-door-vs-digital-leads-where-to-invest-marketing-budget',
        'Guides','Article','4 min read','Door-to-Door vs Digital Leads: Where to Invest | Acme','Digital leads can cost up to $82 in home services with high Google CPCs. Discover the ROI comparison and how to run a high-converting hybrid strategy.',
        'The $82 Question That Could Define Your Next Quarter','["Top-performing contractors combine hyper-local field trust with automated digital follow-ups.","Digital CPCs are surging, resulting in high customer acquisition costs (CAC) for competitive counties.","D2D delivers stable, predictable trust loops ideal for localized storm damage campaigns.","A hybrid model uses D2D for initial relationship building and digital ads/emails for community nurturing."]','You don''t have to choose between field canvassing and digital leads. Acme acts as the connector, letting you map field-captured intelligence into nurturing channels to drive customer referrals.',NULL,NULL,0,'2026-05-22T09:50:48.142Z','2026-05-22T09:50:48.142Z');
INSERT OR REPLACE INTO articles
