        (id,tenant_id,url_sha256,source_id,source_url,title,slug,category,badge,read_time,seo_title,description,hero_angle,highlights_json,content,cta_text,hero_media_id,is_archived,created_at,updated_at)
       VALUES (
        'acme-review-beyond-door-to-door-tracking','usr_admin_demo','40d8a6b608064c3817df4c9861b769f165c2c1df8dc33c551f4d374eab545e02',NULL,'urn:contentforge-seed:acme-review-beyond-door-to-door-tracking','Acme Review: Beyond Just Door-to-Door Tracking','/blog/acme-review-beyond-door-to-door-tracking',
        'Reviews','Review','4 min read','Acme Review: Beyond Just Door-to-Door Tracking | Acme','An in-depth review of Acme''s robust operations: territory controls, team dashboards, visual commission calculators, and mobile offline maps.',
        'More Than a Canvassing App -- An Operating System for Field Sales','["Replace scattered spreadsheets with a centralized, collaborative team workspace.","Drive rep retention with visual, transparent, smart commission milestone calculations.","Gain precise operational visibility into rep metrics (visit outcomes, routing, appointments completed).","Attach custom forms, inspection media, and property roof measurements inside a single lead file."]','Many field tools track coordinates, but Acme operates as a true field OS. It gives contractors the tools to control the storm canvassing, estimate delivery, contract signatures, and payouts effortlessly.',NULL,NULL,0,'2026-05-22T09:50:48.142Z','2026-05-22T09:50:48.142Z');
